// src/shared/infrastructure/middleware/auth.ts
function authMiddleware(roles) {
  return async (c, next) => {
    const authHeader = c.req.header("Authorization");
    if (!authHeader || !authHeader.startsWith("Bearer ")) {
      return c.json({
        success: false,
        error: "Unauthorized: Missing or invalid Authorization header"
      }, 401);
    }
    const token = authHeader.substring(7);
    try {
      const secret = new TextEncoder().encode(process.env.JWT_SECRET || "supersecretjwtkey1234567890!");
      const { payload } = await jwtVerify(token, secret);
      const user = {
        id: payload.id,
        email: payload.email,
        role: payload.role,
        name: payload.name
      };
      if (roles && roles.length > 0 && !roles.includes(user.role)) {
        return c.json({
          success: false,
          error: "Forbidden: Insufficient permissions"
        }, 403);
      }
      c.set("user", user);
      await next();
    } catch {
      return c.json({
        success: false,
        error: "Unauthorized: Invalid or expired token"
      }, 401);
    }
  };
}

// src/auth/adapters/AuthController.ts
var authRouter = new Hono2;
var userRepo = new SqliteUserRepo;
var registerUseCase = new RegisterUseCase(userRepo);
var loginUseCase = new LoginUseCase(userRepo);
authRouter.get("/me", authMiddleware(["admin", "customer"]), async (c) => {
  const user = c.get("user");
  return c.json({
    success: true,
    user: {
      id: user.id,
      email: user.email,
      name: user.name,
      role: user.role
    }
  });
});
var registerSchema = exports_external.object({
  email: exports_external.string().email("Debe ser un correo electr√≥nico v√°lido"),
  password: exports_external.string().min(6, "La contrase√±a debe tener al menos 6 caracteres"),
  name: exports_external.string().min(2, "El nombre debe tener al menos 2 caracteres"),
  phone: exports_external.string().optional(),
  role: exports_external.enum(["admin", "customer"], {
    errorMap: () => ({ message: "El rol debe ser 'admin' o 'customer'" })
  })
});
var loginSchema = exports_external.object({
  email: exports_external.string().email("Debe ser un correo electr√≥nico v√°lido"),
  password: exports_external.string().min(1, "La contrase√±a es obligatoria")
});
authRouter.post("/register", async (c) => {
  try {
    const body = await c.req.json().catch(() => ({}));
    const validation = registerSchema.safeParse(body);
    if (!validation.success) {
      return c.json({
        success: false,
        errors: validation.error.flatten().fieldErrors
      }, 400);
    }
    const user = await registerUseCase.execute(validation.data);
    return c.json({
      success: true,
      user: {
        id: user.id,
        email: user.email,
        name: user.name,
        role: user.role
      }
    }, 201);
  } catch (error51) {
    return c.json({
      success: false,
      error: error51.message
    }, 400);
  }
});
authRouter.post("/login", async (c) => {
  try {
    const body = await c.req.json().catch(() => ({}));
    const validation = loginSchema.safeParse(body);
    if (!validation.success) {
      return c.json({
        success: false,
        errors: validation.error.flatten().fieldErrors
      }, 400);
    }
    const result = await loginUseCase.execute(validation.data);
    return c.json({
      success: true,
      ...result
    }, 200);
  } catch (error51) {
    const status = error51.message === "Invalid credentials" ? 401 : 400;
    return c.json({
      success: false,
      error: error51.message
    }, status);
  }
});

