// src/cart/core/Cart.ts
class Cart {
  id;
  customerId;
  sessionId;
  status;
  createdAt;
  updatedAt;
  items;
  constructor(id, customerId, sessionId, status, createdAt, updatedAt, items = []) {
    this.id = id;
    this.customerId = customerId;
    this.sessionId = sessionId;
    this.status = status;
    this.createdAt = createdAt;
    this.updatedAt = updatedAt;
    this.items = items;
  }
  static create(params) {
    const now = new Date().toISOString();
    return new Cart(params.id, params.customerId ?? null, params.sessionId ?? null, params.status ?? "active", params.createdAt ?? now, params.updatedAt ?? now, params.items ?? []);
  }
  getSubtotal() {
    return this.items.reduce((sum, item) => sum + item.quantity * item.unitPriceSnapshot, 0);
  }
}

// src/cart/core/CartItem.ts
class CartItem {
  id;
  cartId;
  productVariantId;
  quantity;
  unitPriceSnapshot;
  createdAt;
  updatedAt;
  constructor(id, cartId, productVariantId, quantity, unitPriceSnapshot, createdAt, updatedAt) {
    this.id = id;
    this.cartId = cartId;
    this.productVariantId = productVariantId;
    this.quantity = quantity;
    this.unitPriceSnapshot = unitPriceSnapshot;
    this.createdAt = createdAt;
    this.updatedAt = updatedAt;
  }
  static create(params) {
    const now = new Date().toISOString();
    return new CartItem(params.id, params.cartId, params.productVariantId, params.quantity, params.unitPriceSnapshot, params.createdAt ?? now, params.updatedAt ?? now);
  }
}

// src/cart/core/AddToCartUseCase.ts
class AddToCartUseCase {
  cartRepository;
  productRepository;
  constructor(cartRepository, productRepository) {
    this.cartRepository = cartRepository;
    this.productRepository = productRepository;
  }
  async execute(dto) {
    const variant = await this.productRepository.findVariantById(dto.productVariantId);
    if (!variant) {
      throw new Error("Variant not found");
    }
    const product = await this.productRepository.findById(variant.productId);
    if (!product) {
      throw new Error("Product not found");
    }
    let cart = null;
    if (dto.customerId) {
      cart = await this.cartRepository.findActiveByCustomerId(dto.customerId);
    } else if (dto.sessionId) {
      cart = await this.cartRepository.findActiveBySessionId(dto.sessionId);
    }
    if (!cart) {
      cart = Cart.create({
        id: crypto.randomUUID(),
        customerId: dto.customerId,
        sessionId: dto.sessionId,
        status: "active",
        items: []
      });
      await this.cartRepository.save(cart);
    }
    const existingItem = cart.items.find((item) => item.productVariantId === dto.productVariantId);
    const newQuantity = existingItem ? existingItem.quantity + dto.quantity : dto.quantity;
    if (newQuantity > variant.stock) {
      throw new Error(`Insuficient stock for variant ${variant.color.toLowerCase()}-${variant.size}: ${variant.stock} available`);
    }
    const unitPriceSnapshot = product.basePrice + variant.additionalPrice;
    if (existingItem) {
      const updatedItem = CartItem.create({
        ...existingItem,
        quantity: newQuantity,
        unitPriceSnapshot,
        updatedAt: new Date().toISOString()
      });
      await this.cartRepository.saveItem(updatedItem);
    } else {
      const newItem = CartItem.create({
        id: crypto.randomUUID(),
        cartId: cart.id,
        productVariantId: dto.productVariantId,
        quantity: dto.quantity,
        unitPriceSnapshot
      });
      await this.cartRepository.saveItem(newItem);
    }
    const refreshedCart = await this.cartRepository.findById(cart.id);
    if (!refreshedCart) {
      throw new Error("Failed to load updated cart");
    }
    return refreshedCart;
  }
}

// src/cart/core/UpdateCartItemUseCase.ts
class UpdateCartItemUseCase {
  cartRepository;
  productRepository;
  constructor(cartRepository, productRepository) {
    this.cartRepository = cartRepository;
    this.productRepository = productRepository;
  }
  async execute(dto) {
    if (dto.quantity <= 0) {
      throw new Error("Quantity must be greater than 0");
    }
    const cart = await this.cartRepository.findCartByItemId(dto.cartItemId);
    if (!cart) {
      throw new Error("Cart not found");
    }
    const item = cart.items.find((i) => i.id === dto.cartItemId);
    if (!item) {
      throw new Error("Item not found in cart");
    }
    const variant = await this.productRepository.findVariantById(item.productVariantId);
    if (!variant) {
      throw new Error("Product variant not found");
    }
    if (dto.quantity > variant.stock) {
      throw new Error(`Insuficient stock for variant ${variant.color.toLowerCase()}-${variant.size}: ${variant.stock} available`);
    }
    const updatedItem = CartItem.create({
      ...item,
      quantity: dto.quantity,
      updatedAt: new Date().toISOString()
    });
    await this.cartRepository.saveItem(updatedItem);
    const refreshedCart = await this.cartRepository.findById(cart.id);
    if (!refreshedCart) {
      throw new Error("Failed to load updated cart");
    }
    return refreshedCart;
  }
}

// src/cart/core/RemoveFromCartUseCase.ts
class RemoveFromCartUseCase {
  cartRepository;
  constructor(cartRepository) {
    this.cartRepository = cartRepository;
  }
  async execute(dto) {
    const cart = await this.cartRepository.findCartByItemId(dto.cartItemId);
    if (!cart) {
      throw new Error("Cart not found");
    }
    await this.cartRepository.deleteItem(dto.cartItemId);
    const refreshedCart = await this.cartRepository.findById(cart.id);
    if (!refreshedCart) {
      throw new Error("Failed to load updated cart");
    }
    return refreshedCart;
  }
}

