// src/inventory/core/DecrementStockUseCase.ts
class DecrementStockUseCase {
  productRepository;
  inventoryRepository;
  constructor(productRepository, inventoryRepository) {
    this.productRepository = productRepository;
    this.inventoryRepository = inventoryRepository;
  }
  async execute(dto) {
    if (dto.quantity <= 0) {
      throw new Error("Quantity to decrement must be greater than 0");
    }
    const variant = await this.productRepository.findVariantById(dto.productVariantId);
    if (!variant) {
      throw new Error("Product variant not found");
    }
    const previousStock = variant.stock;
    const newStock = previousStock - dto.quantity;
    if (newStock < 0) {
      throw new Error(`Insuficient stock for variant: ${previousStock} available, requested ${dto.quantity}`);
    }
    await this.productRepository.updateVariantStock(dto.productVariantId, newStock);
    const movement = StockMovement.create({
      id: crypto.randomUUID(),
      productVariantId: dto.productVariantId,
      type: "sale",
      quantity: -dto.quantity,
      previousStock,
      newStock,
      referenceType: dto.referenceType,
      referenceId: dto.referenceId,
      createdBy: dto.createdBy
    });
    await this.inventoryRepository.saveMovement(movement);
    const threshold = 5;
    if (newStock < threshold) {
      const activeAlert = await this.inventoryRepository.findActiveAlertByVariantId(dto.productVariantId);
      if (!activeAlert) {
        const newAlert = StockAlert.create({
          id: crypto.randomUUID(),
          productVariantId: dto.productVariantId,
          threshold,
          currentStock: newStock,
          status: "active"
        });
        await this.inventoryRepository.saveAlert(newAlert);
      } else {
        const updatedAlert = StockAlert.create({
          ...activeAlert,
          currentStock: newStock
        });
        await this.inventoryRepository.saveAlert(updatedAlert);
      }
    }
  }
}

// src/orders/adapters/SqliteOrderRepo.ts
class SqliteOrderRepo {
  toDomain(row, itemRows, paymentRows) {
    const items = itemRows.map((item) => new OrderItem(item.id, item.orderId, item.productVariantId, item.productNameSnapshot, item.variantDetailsSnapshot, item.quantity, item.unitPrice, item.subtotal, item.createdAt));
    const payList = paymentRows.map((p) => new Payment(p.id, p.orderId, p.amount, p.currency, p.status, p.method, p.stripeChargeId, p.stripePaymentIntentId, p.errorMessage, p.createdAt, p.updatedAt));
    return new Order(row.id, row.customerId, row.guestEmail, row.guestName, row.guestPhone, row.shippingAddress, row.subtotal, row.total, row.currency, row.status, row.stripePaymentIntentId, row.notes, row.createdAt, row.updatedAt, items, payList);
  }
  async findById(id) {
    const [row] = await db.select().from(orders).where(eq(orders.id, id)).limit(1);
    if (!row)
      return null;
    const itemRows = await db.select().from(orderItems).where(eq(orderItems.orderId, id));
    const paymentRows = await db.select().from(payments).where(eq(payments.orderId, id));
    return this.toDomain(row, itemRows, paymentRows);
  }
  async findByPaymentIntentId(paymentIntentId) {
    const [row] = await db.select().from(orders).where(eq(orders.stripePaymentIntentId, paymentIntentId)).limit(1);
    if (!row)
      return null;
    const itemRows = await db.select().from(orderItems).where(eq(orderItems.orderId, row.id));
    const paymentRows = await db.select().from(payments).where(eq(payments.orderId, row.id));
    return this.toDomain(row, itemRows, paymentRows);
  }
  async save(order) {
    await db.transaction(async (tx) => {
      await tx.insert(orders).values({
        id: order.id,
        customerId: order.customerId,
        guestEmail: order.guestEmail,
        guestName: order.guestName,
        guestPhone: order.guestPhone,
        shippingAddress: order.shippingAddress,
        subtotal: order.subtotal,
        total: order.total,
        currency: order.currency,
        status: order.status,
        stripePaymentIntentId: order.stripePaymentIntentId,
        notes: order.notes,
        createdAt: order.createdAt,
        updatedAt: order.updatedAt
      }).onConflictDoUpdate({
        target: orders.id,
        set: {
          status: order.status,
          updatedAt: new Date().toISOString()
        }
      });
      for (const item of order.items) {
        await tx.insert(orderItems).values({
          id: item.id,
          orderId: item.orderId,
          productVariantId: item.productVariantId,
          productNameSnapshot: item.productNameSnapshot,
          variantDetailsSnapshot: item.variantDetailsSnapshot,
          quantity: item.quantity,
          unitPrice: item.unitPrice,
          subtotal: item.subtotal,
          createdAt: item.createdAt
        }).onConflictDoNothing();
      }
    });
  }
  async savePayment(payment) {
    await db.insert(payments).values({
      id: payment.id,
      orderId: payment.orderId,
      amount: payment.amount,
      currency: payment.currency,
      status: payment.status,
      method: payment.method,
      stripeChargeId: payment.stripeChargeId,
      stripePaymentIntentId: payment.stripePaymentIntentId,
      errorMessage: payment.errorMessage,
      createdAt: payment.createdAt,
      updatedAt: payment.updatedAt
    }).onConflictDoUpdate({
      target: payments.id,
      set: {
        status: payment.status,
        stripeChargeId: payment.stripeChargeId,
        errorMessage: payment.errorMessage,
        updatedAt: new Date().toISOString()
      }
    });
  }
  async list(params) {
    const limit = params.limit ?? 10;
    const offset = params.offset ?? 0;
    const conditions = [];
    if (params.customerId) {
      conditions.push(eq(orders.customerId, params.customerId));
    }
    if (params.status) {
      conditions.push(eq(orders.status, params.status));
    }
    const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
    const [countRow] = await db.select({ count: sql`count(*)` }).from(orders).where(whereClause);
    const total = Number(countRow?.count || 0);
    if (total === 0) {
      return { orders: [], total: 0 };
    }
    const orderRows = await db.select().from(orders).where(whereClause).limit(limit).offset(offset).orderBy(sql`${orders.createdAt} DESC`);
    const orderIds = orderRows.map((o) => o.id);
    const itemRows = await db.select().from(orderItems).where(inArray(orderItems.orderId, orderIds));
    const paymentRows = await db.select().from(payments).where(inArray(payments.orderId, orderIds));
    const mappedOrders = orderRows.map((row) => {
      const oItems = itemRows.filter((i) => i.orderId === row.id);
      const oPayments = paymentRows.filter((p) => p.orderId === row.id);
      return this.toDomain(row, oItems, oPayments);
    });
    return {
      orders: mappedOrders,
      total
    };
  }
}

// src/inventory/adapters/SqliteInventoryRepo.ts
class SqliteInventoryRepo {
  toDomainMovement(row) {
    return new StockMovement(row.id, row.productVariantId, row.type, row.quantity, row.previousStock, row.newStock, row.referenceType, row.referenceId, row.notes, row.createdAt, row.createdBy);
  }
  toDomainAlert(row) {
    return new StockAlert(row.id, row.productVariantId, row.threshold, row.currentStock, row.status, row.createdAt, row.resolvedAt);
  }
  async saveMovement(movement) {
    await db.insert(stockMovements).values({
      id: movement.id,
      productVariantId: movement.productVariantId,
      type: movement.type,
      quantity: movement.quantity,
      previousStock: movement.previousStock,
      newStock: movement.newStock,
      referenceType: movement.referenceType,
      referenceId: movement.referenceId,
      notes: movement.notes,
      createdAt: movement.createdAt,
      createdBy: movement.createdBy
    });
  }
  async saveAlert(alert) {
    await db.insert(stockAlerts).values({
      id: alert.id,
      productVariantId: alert.productVariantId,
      threshold: alert.threshold,
      currentStock: alert.currentStock,
      status: alert.status,
      createdAt: alert.createdAt,
      resolvedAt: alert.resolvedAt
    }).onConflictDoUpdate({
      target: stockAlerts.id,
      set: {
        currentStock: alert.currentStock,
        status: alert.status,
        resolvedAt: alert.resolvedAt
      }
    });
  }
  async findActiveAlertByVariantId(variantId) {
    const [row] = await db.select().from(stockAlerts).where(and(eq(stockAlerts.productVariantId, variantId), eq(stockAlerts.status, "active"))).limit(1);
    if (!row)
      return null;
    return this.toDomainAlert(row);
  }
  async listAlerts(status) {
    const conditions = [];
    if (status) {
      conditions.push(eq(stockAlerts.status, status));
    }
    const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
    const rows = await db.select().from(stockAlerts).where(whereClause);
    return rows.map((r) => this.toDomainAlert(r));
  }
}

// src/orders/adapters/StripePaymentGateway.ts
class StripePaymentGateway {
  stripe;
  isMock = true;
  constructor() {
    const key = process.env.STRIPE_SECRET_KEY;
    if (key && key !== "sk_test_mock_key") {
      this.isMock = false;
      this.stripe = new stripe_esm_node_default(key, {
        apiVersion: "2023-10-16"
      });
    } else {
      this.stripe = new stripe_esm_node_default("sk_test_mock", {
        apiVersion: "2023-10-16"
      });
    }
  }
  async createPaymentIntent(amount, currency, metadata) {
    if (this.isMock) {
      const randomId = crypto.randomUUID().substring(0, 8);
      return {
        id: `pi_mock_${randomId}`,
        clientSecret: `pi_mock_secret_${randomId}_${crypto.randomUUID()}`
      };
    }
    const intent = await this.stripe.paymentIntents.create({
      amount,
      currency: currency.toLowerCase(),
      metadata
    });
    return {
      id: intent.id,
      clientSecret: intent.client_secret || ""
    };
  }
  async retrievePaymentIntentStatus(paymentIntentId) {
    if (this.isMock || paymentIntentId.startsWith("pi_mock_")) {
      const randomChargeId = crypto.randomUUID().substring(0, 8);
      return {
        status: "succeeded",
        chargeId: `ch_mock_${randomChargeId}`
      };
    }
    const intent = await this.stripe.paymentIntents.retrieve(paymentIntentId);
    let status = "unknown";
    if (intent.status === "succeeded")
      status = "succeeded";
    else if (intent.status === "requires_payment_method")
      status = "requires_payment_method";
    else if (intent.status === "processing")
      status = "processing";
    else if (intent.status === "canceled")
      status = "canceled";
    const chargeId = typeof intent.latest_charge === "string" ? intent.latest_charge : null;
    return {
      status,
      chargeId,
      errorMessage: intent.last_payment_error?.message
    };
  }
}

