ordersRouter.get("/orders/:id", async (c) => {
  try {
    const id = c.req.param("id");
    const order = await orderRepo.findById(id);
    if (!order) {
      return c.json({ success: false, error: "Order not found" }, 404);
    }
    const authHeader = c.req.header("Authorization");
    const customerId = await getCustomerId2(authHeader);
    let isAdmin = false;
    if (authHeader && authHeader.startsWith("Bearer ")) {
      try {
        const token = authHeader.substring(7);
        const secret = new TextEncoder().encode(process.env.JWT_SECRET || "supersecretjwtkey1234567890!");
        const { payload } = await jwtVerify(token, secret);
        isAdmin = payload.role === "admin";
      } catch {}
    }
    if (!isAdmin && order.customerId && order.customerId !== customerId) {
      return c.json({ success: false, error: "Forbidden: You do not own this order" }, 403);
    }
    return c.json({ success: true, order }, 200);
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 500);
  }
});
ordersRouter.patch("/orders/:id/status", authMiddleware(["admin"]), async (c) => {
  try {
    const id = c.req.param("id");
    const body = await c.req.json().catch(() => ({}));
    const validation = updateStatusSchema.safeParse(body);
    if (!validation.success) {
      return c.json({ success: false, errors: validation.error.flatten().fieldErrors }, 400);
    }
    const order = await orderRepo.findById(id);
    if (!order) {
      return c.json({ success: false, error: "Order not found" }, 404);
    }
    const currentStatus = order.status;
    const newStatus = validation.data.status;
    const allowedTransitions = {
      pendiente: ["pagado", "cancelado", "fallido"],
      pagado: ["enviado", "cancelado"],
      enviado: ["entregado"],
      entregado: [],
      cancelado: [],
      fallido: []
    };
    if (!allowedTransitions[currentStatus]?.includes(newStatus)) {
      return c.json({
        success: false,
        error: `Transici√≥n de estado inv√°lida: de '${currentStatus}' a '${newStatus}'`
      }, 400);
    }
    const updatedOrder = Order.create({
      ...order,
      status: newStatus,
      updatedAt: new Date().toISOString()
    });
    await orderRepo.save(updatedOrder);
    if (newStatus === "pagado" && currentStatus === "pendiente") {
      for (const item of order.items) {
        await decrementStockUseCase.execute({
          productVariantId: item.productVariantId,
          quantity: item.quantity,
          referenceType: "order",
          referenceId: order.id
        });
      }
      const payment = Payment.create({
        id: crypto.randomUUID(),
        orderId: order.id,
        amount: order.total,
        currency: order.currency,
        status: "succeeded",
        method: "manual"
      });
      await orderRepo.savePayment(payment);
      let cart = null;
      if (order.customerId) {
        cart = await cartRepo2.findActiveByCustomerId(order.customerId);
      } else if (order.items.length > 0 && order.items[0]) {
        cart = await cartRepo2.findActiveCartByVariantId(order.items[0].productVariantId);
      }
      if (cart) {
        const convertedCart = Cart.create({
          ...cart,
          status: "converted",
          updatedAt: new Date().toISOString()
        });
        await cartRepo2.save(convertedCart);
        await cartRepo2.deleteItemsByCartId(cart.id);
      }
    }
    if (newStatus === "cancelado" && currentStatus === "pagado") {
      for (const item of order.items) {
        const variant = await productRepo3.findVariantById(item.productVariantId);
        if (variant) {
          const restoredStock = variant.stock + item.quantity;
          await productRepo3.updateVariantStock(item.productVariantId, restoredStock);
          const restoreMovement = {
            id: crypto.randomUUID(),
            productVariantId: item.productVariantId,
            type: "cancellation",
            quantity: item.quantity,
            previousStock: variant.stock,
            newStock: restoredStock,
            referenceType: "order",
            referenceId: order.id,
            notes: "Restocked due to order cancellation",
            createdAt: new Date().toISOString(),
            createdBy: c.get("user")?.id || null
          };
          await inventoryRepo.saveMovement(restoreMovement);
        }
      }
    }
    return c.json({ success: true, order: updatedOrder }, 200);
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 400);
  }
});
ordersRouter.post("/payments/webhook", async (c) => {
  const stripeSecret = process.env.STRIPE_SECRET_KEY;
  const webhookSecret = process.env.STRIPE_WEBHOOK_SECRET;
  const signature = c.req.header("stripe-signature");
  if (!stripeSecret || stripeSecret === "sk_test_mock_key" || !webhookSecret || !signature) {
    try {
      const body = await c.req.json().catch(() => ({}));
      if (body.type === "payment_intent.succeeded") {
        const paymentIntentId = body.data?.object?.id;
        if (paymentIntentId) {
          await confirmPaymentUseCase.execute({ stripePaymentIntentId: paymentIntentId });
          return c.json({ received: true, mocked: true });
        }
      }
      return c.json({ received: true, message: "Mock webhook ignored or processed" });
    } catch (error51) {
      return c.json({ error: error51.message }, 400);
    }
  }
  try {
    const rawBody = await c.req.text();
    const stripe = new stripe_esm_node_default(stripeSecret, { apiVersion: "2023-10-16" });
    const event = stripe.webhooks.constructEvent(rawBody, signature, webhookSecret);
    if (event.type === "payment_intent.succeeded") {
      const paymentIntent = event.data.object;
      await confirmPaymentUseCase.execute({ stripePaymentIntentId: paymentIntent.id });
    } else if (event.type === "payment_intent.payment_failed") {
      const paymentIntent = event.data.object;
      try {
        await confirmPaymentUseCase.execute({ stripePaymentIntentId: paymentIntent.id });
      } catch {}
    }
    return c.json({ received: true });
  } catch (error51) {
    return c.json({ error: `Webhook Error: ${error51.message}` }, 400);
  }
});

// src/dashboard/adapters/DashboardController.ts
var dashboardRouter = new Hono2;
dashboardRouter.use("*", authMiddleware(["admin"]));
dashboardRouter.get("/metrics", async (c) => {
  try {
    const [salesRow] = await db.select({
      totalSales: sql`sum(${orders.total})`,
      count: sql`count(*)`,
      avgTicket: sql`avg(${orders.total})`
    }).from(orders).where(sql`${orders.status} IN ('pagado', 'enviado', 'entregado')`);
    const [lowStockRow] = await db.select({ count: sql`count(*)` }).from(productVariants).where(sql`${productVariants.stock} < 5`);
    return c.json({
      success: true,
      metrics: {
        totalSales: Number(salesRow?.totalSales || 0),
        orderCount: Number(salesRow?.count || 0),
        averageTicket: Math.round(Number(salesRow?.avgTicket || 0)),
        lowStockCount: Number(lowStockRow?.count || 0)
      }
    });
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 500);
  }
});
dashboardRouter.get("/top-products", async (c) => {
  try {
    const list = await db.select({
      productId: productVariants.productId,
      productName: orderItems.productNameSnapshot,
      totalQuantity: sql`sum(${orderItems.quantity})`,
      revenue: sql`sum(${orderItems.subtotal})`
    }).from(orderItems).innerJoin(orders, eq(orderItems.orderId, orders.id)).innerJoin(productVariants, eq(orderItems.productVariantId, productVariants.id)).where(sql`${orders.status} IN ('pagado', 'enviado', 'entregado')`).groupBy(productVariants.productId, orderItems.productNameSnapshot).orderBy(sql`sum(${orderItems.quantity}) DESC`).limit(5);
    const formatted = list.map((item) => ({
      productId: item.productId,
      productName: item.productName,
      totalQuantity: Number(item.totalQuantity || 0),
      revenue: Number(item.revenue || 0)
    }));
    return c.json({ success: true, topProducts: formatted });
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 500);
  }
});
dashboardRouter.get("/orders-by-status", async (c) => {
  try {
    const list = await db.select({
      status: orders.status,
      count: sql`count(*)`
    }).from(orders).groupBy(orders.status);
    const result = {
      pendiente: 0,
      pagado: 0,
      enviado: 0,
      entregado: 0,
      cancelado: 0,
      fallido: 0
    };
    for (const item of list) {
      if (item.status && item.status in result) {
        result[item.status] = Number(item.count || 0);
      }
    }
    return c.json({ success: true, statusDistribution: result });
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 500);
  }
});
dashboardRouter.get("/sales-timeline", async (c) => {
  try {
    const interval = c.req.query("interval") || "daily";
    let dateGroup = sql`strftime('%Y-%m-%d', ${orders.createdAt})`;
    if (interval === "monthly") {
      dateGroup = sql`strftime('%Y-%m', ${orders.createdAt})`;
    } else if (interval === "weekly") {
      dateGroup = sql`strftime('%Y-W%W', ${orders.createdAt})`;
    }
    const list = await db.select({
      period: dateGroup,
      revenue: sql`sum(${orders.total})`,
      count: sql`count(*)`
    }).from(orders).where(sql`${orders.status} IN ('pagado', 'enviado', 'entregado')`).groupBy(dateGroup).orderBy(dateGroup);
    const formatted = list.map((item) => ({
      period: item.period,
      revenue: Number(item.revenue || 0),
      count: Number(item.count || 0)
    }));
    return c.json({ success: true, timeline: formatted });
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 500);
  }
});

// src/inventory/adapters/InventoryController.ts
var inventoryRouter = new Hono2;
var inventoryRepo2 = new SqliteInventoryRepo;
var productRepo4 = new SqliteProductRepo;
inventoryRouter.use("*", authMiddleware(["admin"]));
var restockSchema = exports_external.object({
  productVariantId: exports_external.string().uuid("El id de la variante debe ser un UUID v√°lido"),
  quantity: exports_external.number().int().positive("La cantidad a reabastecer debe ser mayor a 0"),
  notes: exports_external.string().optional()
});
inventoryRouter.get("/alerts", async (c) => {
  try {
    const alerts = await inventoryRepo2.listAlerts("active");
    return c.json({ success: true, alerts });
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 500);
  }
});
inventoryRouter.post("/restock", async (c) => {
  try {
    const body = await c.req.json().catch(() => ({}));
    const validation = restockSchema.safeParse(body);
    if (!validation.success) {
      return c.json({ success: false, errors: validation.error.flatten().fieldErrors }, 400);
    }
    const { productVariantId, quantity, notes } = validation.data;
    const variant = await productRepo4.findVariantById(productVariantId);
    if (!variant) {
      return c.json({ success: false, error: "Product variant not found" }, 404);
    }
    const previousStock = variant.stock;
    const newStock = previousStock + quantity;
    await productRepo4.updateVariantStock(productVariantId, newStock);
    const movement = StockMovement.create({
      id: crypto.randomUUID(),
      productVariantId,
      type: "restock",
      quantity,
      previousStock,
      newStock,
      referenceType: "restock",
      notes: notes || "Manual restock",
      createdBy: c.get("user")?.id || null
    });
    await inventoryRepo2.saveMovement(movement);
    if (newStock >= 5) {
      const activeAlert = await inventoryRepo2.findActiveAlertByVariantId(productVariantId);
      if (activeAlert) {
        const resolvedAlert = StockAlert.create({
          ...activeAlert,
          status: "resolved",
          resolvedAt: new Date().toISOString()
        });
        await inventoryRepo2.saveAlert(resolvedAlert);
      }
    }
    return c.json({
      success: true,
      message: `Restocked ${quantity} units successfully. New stock: ${newStock}`
    });
  } catch (error51) {
    return c.json({ success: false, error: error51.message }, 400);
  }
});

